105	// StringToModelOrTimeDurationHookFunc returns a DecodeHookFuncType
106	// that converts string to time.Duration, which can also be used
107	// as model.Duration.
108	func StringToModelOrTimeDurationHookFunc() mapstructure.DecodeHookFuncType {
109		return func(
110			f reflect.Type,
111			t reflect.Type,
112			data any,
113		) (any, error) {
114			if f.Kind() != reflect.String {
115				return data, nil
116			}
117	
118			if t != reflect.TypeFor[model.Duration]() && t != reflect.TypeFor[time.Duration]() {
119				return data, nil
120			}
121	
122			return time.ParseDuration(data.(string))
123		}
124	}
