126	// MapToPromConfig returns a DecodeHookFuncType that provides a mechanism
127	// for decoding promconfig.Config involving its own unmarshal logic.
128	func MapToPromConfig() mapstructure.DecodeHookFuncType {
129		return func(
130			f reflect.Type,
131			t reflect.Type,
132			data any,
133		) (any, error) {
134			if f.Kind() != reflect.Map {
135				return data, nil
136			}
137	
138			if t != reflect.TypeFor[*promconfig.Config]() {
139				return data, nil
140			}
141	
142			dataMap := data.(map[any]any)
143			mb, err := yaml.Marshal(dataMap)
144			if err != nil {
145				return nil, err
146			}
147	
148			pConfig := &promconfig.Config{}
149			err = yaml.Unmarshal(mb, pConfig)
150			if err != nil {
151				return nil, err
152			}
153			return pConfig, nil
154		}
155	}
