157	const monitoringV1PkgPath = "github.com/prometheus-operator/prometheus-operator/pkg/apis/monitoring/v1"
158	
159	// MapToMonitoringV1 handles prom-operator types that use json:",inline" for embedded structs.
160	// mapstructure with TagName:"yaml" can't squash these, so we round-trip through sigs.k8s.io/yaml
161	// which converts YAML → JSON → json.Unmarshal, correctly handling json:",inline".
162	func MapToMonitoringV1() mapstructure.DecodeHookFuncType {
163		return func(
164			f reflect.Type,
165			t reflect.Type,
166			data any,
167		) (any, error) {
168			if f.Kind() != reflect.Map {
169				return data, nil
170			}
171			target := t
172			if t.Kind() == reflect.Pointer {
173				target = t.Elem()
174			}
175			if target.PkgPath() != monitoringV1PkgPath {
176				return data, nil
177			}
178			yamlBytes, err := yaml.Marshal(data)
179			if err != nil {
180				return data, err
181			}
182			result := reflect.New(target)
183			if err := sigsyaml.Unmarshal(yamlBytes, result.Interface()); err != nil {
184				return data, err
185			}
186			if t.Kind() == reflect.Pointer {
187				return result.Interface(), nil
188			}
189			return result.Elem().Interface(), nil
190		}
191	}
