193	// MapToLabelSelector returns a DecodeHookFuncType that
194	// provides a mechanism for decoding both matchLabels and matchExpressions from camelcase to lowercase
195	// because we use yaml unmarshaling that supports lowercase field names if no `yaml` tag is defined
196	// and metav1.LabelSelector uses `json` tags.
197	// If both the camelcase and lowercase version is present, then the camelcase version takes precedence.
198	func MapToLabelSelector() mapstructure.DecodeHookFuncType {
199		return func(
200			f reflect.Type,
201			t reflect.Type,
202			data any,
203		) (any, error) {
204			if f.Kind() != reflect.Map {
205				return data, nil
206			}
207	
208			if t != reflect.TypeFor[*metav1.LabelSelector]() {
209				return data, nil
210			}
211	
212			result := &metav1.LabelSelector{}
213			fMap := data.(map[any]any)
214			if matchLabels, ok := fMap["matchLabels"]; ok {
215				fMap["matchlabels"] = matchLabels
216				delete(fMap, "matchLabels")
217			}
218			if matchExpressions, ok := fMap["matchExpressions"]; ok {
219				fMap["matchexpressions"] = matchExpressions
220				delete(fMap, "matchExpressions")
221			}
222	
223			b, err := yaml.Marshal(fMap)
224			if err != nil {
225				return nil, err
226			}
227	
228			err = yaml.Unmarshal(b, result)
229			if err != nil {
230				return nil, err
231			}
232			return result, nil
233		}
234	}
