319	// unmarshal decodes the contents of the configFile into the cfg argument, using a
320	// mapstructure decoder with the following notable behaviors.
321	// Decodes time.Duration from strings (see StringToModelDurationHookFunc).
322	// Allows custom unmarshaling for promconfig.Config struct that implements yaml.Unmarshaler (see MapToPromConfig).
323	// Allows custom unmarshaling for metav1.LabelSelector struct using both camelcase and lowercase field names (see MapToLabelSelector).
324	func unmarshal(cfg *Config, configFile string) error {
325		yamlFile, err := os.ReadFile(configFile)
326		if err != nil {
327			return err
328		}
329	
330		m := make(map[string]any)
331		err = yaml.Unmarshal(yamlFile, &m)
332		if err != nil {
333			return fmt.Errorf("error unmarshaling YAML: %w", err)
334		}
335	
336		dc := mapstructure.DecoderConfig{
337			TagName: "yaml",
338			Result:  cfg,
339			DecodeHook: mapstructure.ComposeDecodeHookFunc(
340				StringToModelOrTimeDurationHookFunc(),
341				MapToPromConfig(),
342				MapToMonitoringV1(),
343				MapToLabelSelector(),
344			),
345		}
346	
347		decoder, err := mapstructure.NewDecoder(&dc)
348		if err != nil {
349			return err
350		}
351		return decoder.Decode(m)
352	}
