425	func (c HTTPSServerConfig) NewTLSConfig(logger logr.Logger) (*tls.Config, *certwatcher.CertWatcher, error) {
426		// Create certwatcher for server certificate/key reloading
427		certWatcher, err := certwatcher.New(c.TLSCertFilePath, c.TLSKeyFilePath)
428		if err != nil {
429			return nil, nil, fmt.Errorf("failed to create cert watcher: %w", err)
430		}
431	
432		// Create CA reloader for client CA certificate reloading
433		caReloader, err := NewCAReloader(c.CAFilePath, logger)
434		if err != nil {
435			return nil, nil, fmt.Errorf("failed to create CA reloader: %w", err)
436		}
437	
438		// Register callback to reload CA when server cert changes
439		// Since Kubernetes updates secrets atomically, the CA will be updated at the same time
440		certWatcher.RegisterCallback(func(tls.Certificate) {
441			if reloadErr := caReloader.Reload(); reloadErr != nil {
442				logger.Error(reloadErr, "Failed to reload CA via callback")
443			}
444		})
445	
446		tlsConfig := &tls.Config{
447			GetCertificate: certWatcher.GetCertificate,
448			// Request client certificate but don't verify automatically
449			// We'll do custom verification in VerifyConnection with the dynamic CA pool
450			ClientAuth: tls.RequestClientCert,
451			MinVersion: tls.VersionTLS12,
452			// Use VerifyConnection for dynamic CA pool access
453			// This allows the CA pool to be reloaded at runtime
454			VerifyConnection: func(cs tls.ConnectionState) error {
455				// Require client certificate
456				if len(cs.PeerCertificates) == 0 {
457					return errors.New("no client certificate provided")
458				}
459	
460				// Verify using current CA pool (which can be reloaded)
461				opts := x509.VerifyOptions{
462					Roots:         caReloader.GetClientCAs(),
463					Intermediates: x509.NewCertPool(),
464					KeyUsages:     []x509.ExtKeyUsage{x509.ExtKeyUsageClientAuth},
465				}
466	
467				// Add intermediate certificates to the pool
468				for _, cert := range cs.PeerCertificates[1:] {
469					opts.Intermediates.AddCert(cert)
470				}
471	
472				// Verify only the leaf certificate
473				if _, err := cs.PeerCertificates[0].Verify(opts); err != nil {
474					return fmt.Errorf("client certificate verification failed: %w", err)
475				}
476				return nil
477			},
478		}
479	
480		return tlsConfig, certWatcher, nil
481	}
