483	// GetSecretsAllowList returns the namespaces to watch for secrets as a map.
484	// If SecretNamespaces is explicitly configured, those namespaces are used.
485	// Otherwise, it defaults to the collectorNamespace (the target allocator's own namespace).
486	func (c PrometheusCRConfig) GetSecretsAllowList(collectorNamespace string) map[string]struct{} {
487		secretsAllowList := make(map[string]struct{})
488		if len(c.SecretNamespaces) > 0 {
489			for _, ns := range c.SecretNamespaces {
490				secretsAllowList[ns] = struct{}{}
491			}
492		} else if collectorNamespace != "" {
493			secretsAllowList[collectorNamespace] = struct{}{}
494		}
495		return secretsAllowList
496	}
