63	
64		if len(globalConfig) > 0 {
65			config["global"] = globalConfig
66		}
67	
68		if len(scrapeConfigs) > 0 {
69			config["scrape_configs"] = scrapeConfigs
70		}
71	
72		if len(config) != 0 {
73			taConfig["config"] = config
74		}
75	
76		taConfig["collector_selector"] = collectorSelector
77	
78		if len(taSpec.AllocationStrategy) > 0 {
79			taConfig["allocation_strategy"] = taSpec.AllocationStrategy
80		} else {
81			taConfig["allocation_strategy"] = v1beta1.TargetAllocatorAllocationStrategyConsistentHashing
82		}
83	
84		if featuregate.EnableTargetAllocatorFallbackStrategy.IsEnabled() {
85			taConfig["allocation_fallback_strategy"] = v1beta1.TargetAllocatorAllocationStrategyConsistentHashing
86		}
87	
88		taConfig["filter_strategy"] = taSpec.FilterStrategy
89	
90		if taSpec.PrometheusCR.Enabled {
91			prometheusCRConfig := map[any]any{
92				"enabled": true,
93			}
94			if taSpec.PrometheusCR.ScrapeInterval.Size() > 0 {
95				prometheusCRConfig["scrape_interval"] = taSpec.PrometheusCR.ScrapeInterval.Duration
96			}
97			if taSpec.PrometheusCR.EvaluationInterval.Size() > 0 {
98				prometheusCRConfig["evaluation_interval"] = taSpec.PrometheusCR.EvaluationInterval.Duration
99			}
100			if taSpec.PrometheusCR.ScrapeProtocols != nil {
101				prometheusCRConfig["scrape_protocols"] = taSpec.PrometheusCR.ScrapeProtocols
102			}
103	
104			if taSpec.PrometheusCR.ScrapeClasses != nil {
105				prometheusCRConfig["scrape_classes"] = taSpec.PrometheusCR.ScrapeClasses
106			}
107	
108			if taSpec.PrometheusCR.AllowNamespaces != nil {
109				prometheusCRConfig["allow_namespaces"] = taSpec.PrometheusCR.AllowNamespaces
110			}
111	
112			if taSpec.PrometheusCR.DenyNamespaces != nil {
113				prometheusCRConfig["deny_namespaces"] = taSpec.PrometheusCR.DenyNamespaces
114			}
115	
116			if taSpec.PrometheusCR.SecretNamespaces != nil {
117				prometheusCRConfig["secret_namespaces"] = taSpec.PrometheusCR.SecretNamespaces
118			}
119	
120			prometheusCRConfig["service_monitor_namespace_selector"] = taSpec.PrometheusCR.ServiceMonitorNamespaceSelector
121			prometheusCRConfig["service_monitor_selector"] = taSpec.PrometheusCR.ServiceMonitorSelector
122	
123			prometheusCRConfig["pod_monitor_namespace_selector"] = taSpec.PrometheusCR.PodMonitorNamespaceSelector
124			prometheusCRConfig["pod_monitor_selector"] = taSpec.PrometheusCR.PodMonitorSelector
125	
126			prometheusCRConfig["scrape_config_namespace_selector"] = taSpec.PrometheusCR.ScrapeConfigNamespaceSelector
127			prometheusCRConfig["scrape_config_selector"] = taSpec.PrometheusCR.ScrapeConfigSelector
128	
129			prometheusCRConfig["probe_namespace_selector"] = taSpec.PrometheusCR.ProbeNamespaceSelector
130			prometheusCRConfig["probe_selector"] = taSpec.PrometheusCR.ProbeSelector
131	
132			taConfig["prometheus_cr"] = prometheusCRConfig
133		}
134	
135		if params.Config.CertManagerAvailability == certmanager.Available && featuregate.EnableTargetAllocatorMTLS.IsEnabled() {
136			taConfig["https"] = map[string]any{
137				"enabled":            true,
138				"listen_addr":        ":8443",
139				"ca_file_path":       filepath.Join(constants.TACollectorTLSDirPath, constants.TACollectorCAFileName),
140				"tls_cert_file_path": filepath.Join(constants.TACollectorTLSDirPath, constants.TACollectorTLSCertFileName),
141				"tls_key_file_path":  filepath.Join(constants.TACollectorTLSDirPath, constants.TACollectorTLSKeyFileName),
142			}
143		}
144	
145		if taSpec.CollectorNotReadyGracePeriod.Size() > 0 {
146			taConfig["collector_not_ready_grace_period"] = taSpec.CollectorNotReadyGracePeriod.Duration
147		}
148	
149		taConfigYAML, err := yaml.Marshal(taConfig)
150		if err != nil {
151			return &corev1.ConfigMap{}, err
152		}
153	
154		return &corev1.ConfigMap{
155			ObjectMeta: metav1.ObjectMeta{
156				Name:        name,
157				Namespace:   instance.Namespace,
158				Labels:      labels,
159				Annotations: instance.Annotations,
160			},
161			Data: map[string]string{
162				targetAllocatorFilename: string(taConfigYAML),
163			},
164		}, nil
165	}
