167	func getGlobalConfig(taGlobalConfig v1beta1.AnyConfig, collectorConfig v1beta1.Config) (map[string]any, error) {
168		// global config from the target allocator has priority
169		if len(taGlobalConfig.Object) > 0 {
170			return taGlobalConfig.Object, nil
171		}
172	
173		collectorGlobalConfig, err := getGlobalConfigFromOtelConfig(collectorConfig)
174		if err != nil {
175			return nil, err
176		}
177		return collectorGlobalConfig.Object, nil
178	}
