180	func getScrapeConfigs(taScrapeConfigs []v1beta1.AnyConfig, collectorConfig v1beta1.Config) ([]v1beta1.AnyConfig, error) {
181		scrapeConfigs := []v1beta1.AnyConfig{}
182	
183		// we take scrape configs from both the target allocator spec and the collector config
184		if len(taScrapeConfigs) > 0 {
185			scrapeConfigs = append(scrapeConfigs, taScrapeConfigs...)
186		}
187	
188		configStr, err := otelconfig.Yaml(&collectorConfig)
189		if err != nil {
190			return nil, err
191		}
192	
193		collectorScrapeConfigs, err := getScrapeConfigsFromOtelConfig(configStr)
194		if err != nil {
195			return nil, err
196		}
197	
198		return append(scrapeConfigs, collectorScrapeConfigs...), nil
199	}
200	
201	func getGlobalConfigFromOtelConfig(otelConfig v1beta1.Config) (v1beta1.AnyConfig, error) {
202		// TODO: Eventually we should figure out a way to pull this in to the main specification for the TA
203		type promReceiverConfig struct {
204			Prometheus struct {
205				Config struct {
206					Global map[string]any `mapstructure:"global"`
207				} `mapstructure:"config"`
208			} `mapstructure:"prometheus"`
209		}
210		decodedConfig := &promReceiverConfig{}
211		if err := mapstructure.Decode(otelConfig.Receivers.Object, decodedConfig); err != nil {
212			return v1beta1.AnyConfig{}, err
213		}
214		return v1beta1.AnyConfig{
215			Object: decodedConfig.Prometheus.Config.Global,
216		}, nil
217	}
218	
219	func getScrapeConfigsFromOtelConfig(otelcolConfig string) ([]v1beta1.AnyConfig, error) {
220		// Collector supports environment variable substitution, but the TA does not.
221		// TA Scrape Configs should have a single "$", as it does not support env var substitution
222		prometheusReceiverConfig, err := adapters.UnescapeDollarSignsInPromConfig(otelcolConfig)
223		if err != nil {
224			return nil, err
225		}
226	
227		scrapeConfigs, err := adapters.GetScrapeConfigsFromPromConfig(prometheusReceiverConfig)
228		if err != nil {
229			return nil, err
230		}
231	
232		v1beta1scrapeConfigs := make([]v1beta1.AnyConfig, len(scrapeConfigs))
233	
234		for i, config := range scrapeConfigs {
235			v1beta1scrapeConfigs[i] = v1beta1.AnyConfig{Object: config}
236		}
237	
238		return v1beta1scrapeConfigs, nil
239	}
