147	// RemoveRegexFromRelabelAction is needed specifically for keepequal/dropequal actions because even though the user doesn't specify the
148	// regex field for these actions the unmarshalling implementations of prometheus adds back the default regex fields
149	// which in turn causes the receiver to error out since the unmarshaling of the json response doesn't expect anything in the regex fields
150	// for these actions. Adding this as a fix until the original issue with prometheus unmarshaling is fixed -
151	// https://github.com/prometheus/prometheus/issues/12534
152	func RemoveRegexFromRelabelAction(jsonConfig []byte) ([]byte, error) {
153		var jobToScrapeConfig map[string]any
154		err := json.Unmarshal(jsonConfig, &jobToScrapeConfig)
155		if err != nil {
156			return nil, err
157		}
158		for _, scrapeConfig := range jobToScrapeConfig {
159			scrapeConfig := scrapeConfig.(map[string]any)
160			if scrapeConfig["relabel_configs"] != nil {
161				relabelConfigs := scrapeConfig["relabel_configs"].([]any)
162				for _, relabelConfig := range relabelConfigs {
163					relabelConfig := relabelConfig.(map[string]any)
164					// Dropping regex key from the map since unmarshalling this on the client(metrics_receiver.go) results in error
165					// because of the bug here - https://github.com/prometheus/prometheus/issues/12534
166					if relabelConfig["action"] == "keepequal" || relabelConfig["action"] == "dropequal" {
167						delete(relabelConfig, "regex")
168					}
169				}
170			}
171			if scrapeConfig["metric_relabel_configs"] != nil {
172				metricRelabelConfigs := scrapeConfig["metric_relabel_configs"].([]any)
173				for _, metricRelabelConfig := range metricRelabelConfigs {
174					metricRelabelConfig := metricRelabelConfig.(map[string]any)
175					// Dropping regex key from the map since unmarshalling this on the client(metrics_receiver.go) results in error
176					// because of the bug here - https://github.com/prometheus/prometheus/issues/12534
177					if metricRelabelConfig["action"] == "keepequal" || metricRelabelConfig["action"] == "dropequal" {
178						delete(metricRelabelConfig, "regex")
179					}
180				}
181			}
182		}
183	
184		jsonConfigNew, err := json.Marshal(jobToScrapeConfig)
185		if err != nil {
186			return nil, err
187		}
188		return jsonConfigNew, nil
189	}
