221	// UpdateScrapeConfigResponse updates the scrape config response. The target allocator first marshals these
222	// configurations such that the underlying prometheus marshaling is used. After that, the YAML is converted
223	// in to a JSON format for consumers to use.
224	func (s *Server) UpdateScrapeConfigResponse(configs map[string]*promconfig.ScrapeConfig) error {
225		err := s.MarshalScrapeConfig(configs, false)
226		if err != nil {
227			return err
228		}
229		err = s.MarshalScrapeConfig(configs, true)
230		if err != nil {
231			return err
232		}
233		return nil
234	}
