236	// ScrapeConfigsHandler returns the available scrape configuration discovered by the target allocator.
237	func (s *Server) ScrapeConfigsHandler(c *gin.Context) {
238		if strings.Contains(c.Request.Header.Get("Accept"), "text/html") {
239			s.ScrapeConfigsHTMLHandler(c)
240			return
241		}
242		s.mtx.RLock()
243		result := s.scrapeConfigResponse
244		if c.Request.TLS != nil {
245			result = s.ScrapeConfigMarshalledSecretResponse
246		}
247		s.mtx.RUnlock()
248	
249		// We don't use the jsonHandler method because we don't want our bytes to be re-encoded
250		c.Writer.Header().Set("Content-Type", "application/json")
251		_, err := c.Writer.Write(result)
252		if err != nil {
253			s.errorHandler(c.Writer, err)
254		}
255	}
