292	// IndexHandler displays the main page of the allocator. It shows the number of jobs and targets.
293	// It also displays a table with the collectors and the number of jobs and targets for each collector.
294	// The collector names are links to the respective pages. The table is sorted by collector name.
295	func (s *Server) IndexHandler(c *gin.Context) {
296		c.Writer.Header().Set("Content-Type", "text/html")
297		WriteHTMLPageHeader(c.Writer, HeaderData{
298			Title: "OpenTelemetry Target Allocator",
299		})
300	
301		WriteHTMLPropertiesTable(c.Writer, PropertiesTableData{
302			Headers: []string{"Category", "Count"},
303			Rows: [][]Cell{
304				{scrapeConfigAnchorLink(), Text(strconv.Itoa(s.getScrapeConfigCount()))},
305				{jobsAnchorLink(), Text(strconv.Itoa(s.getJobCount()))},
306				{targetsAnchorLink(), Text(strconv.Itoa(len(s.allocator.TargetItems())))},
307			},
308		})
309		WriteHTMLPropertiesTable(c.Writer, PropertiesTableData{
310			Headers: []string{"Collector", "Job Count", "Target Count"},
311			Rows: func() [][]Cell {
312				var rows [][]Cell
313				collectorNames := []string{}
314				for k := range s.allocator.Collectors() {
315					collectorNames = append(collectorNames, k)
316				}
317				slices.Sort(collectorNames)
318	
319				for _, colName := range collectorNames {
320					jobCount := strconv.Itoa(s.getJobCountForCollector(colName))
321					targetCount := strconv.Itoa(s.getTargetCountForCollector(colName))
322					rows = append(rows, []Cell{collectorAnchorLink(colName), NewCell(jobCount), NewCell(targetCount)})
323				}
324				return rows
325			}(),
326		})
327		WriteHTMLPageFooter(c.Writer)
328	}
