373	// TargetHTMLHandler displays information about a target in a table format.
374	// There are two tables: one for high-level target information and another for the target's labels.
375	func (s *Server) TargetHTMLHandler(c *gin.Context) {
376		c.Writer.Header().Set("X-Content-Type-Options", "nosniff")
377		c.Writer.Header().Set("Content-Type", "text/html; charset=utf-8")
