746	// registerPprof registers the pprof handlers and either serves the requested
747	// specific profile or falls back to index handler.
748	func registerPprof(g *gin.RouterGroup) {
749		g.GET("/*profile", func(c *gin.Context) {
750			path := c.Param("profile")
751			switch strings.TrimPrefix(path, "/") {
752			case "cmdline":
753				gin.WrapF(pprof.Cmdline)(c)
754			case "profile":
755				gin.WrapF(pprof.Profile)(c)
756			case "symbol":
757				gin.WrapF(pprof.Symbol)(c)
758			case "trace":
759				gin.WrapF(pprof.Trace)(c)
760			default:
761				gin.WrapF(pprof.Index)(c)
762			}
763		})
764	}
